patch:
--- a/register.sv
+++ b/register.sv
@@ -1,12 +1,12 @@
 module reg_32(
-  input [31:0] data_in,
-  output [31:0] data_out,
+  output [31:0] data_in,
+  input [31:0] data_out,
   input clk
 );
   reg [31:0] storage;
   always @(posedge clk) begin
-    storage <= data_in;
+    storage <= data_out;
   end
-  assign data_out = storage;
+  assign data_in = storage;
 endmodule

 module sys(
@@ -15,7 +15,7 @@ module sys(
   output [31:0] q
 );
   wire [31:0] d_in, d_out;
-  reg_32 r1(.data_in(d), .data_out(q), .clk(clk));
+  reg_32 r1(.data_out(d), .data_in(q), .clk(clk));
 endmodule

before_code:
module reg_32(
  input [31:0] data_in,
  output [31:0] data_out,
  input clk
);
  reg [31:0] storage;
  always @(posedge clk) begin
    storage <= data_in;
  end
  assign data_out = storage;
endmodule

module sys(
  input clk,
  input [31:0] d,
  output [31:0] q
);
  wire [31:0] d_in, d_out;
  reg_32 r1(.data_in(d), .data_out(q), .clk(clk));
endmodule

after_code:
module reg_32(
  output [31:0] data_in,
  input [31:0] data_out,
  input clk
);
  reg [31:0] storage;
  always @(posedge clk) begin
    storage <= data_out;
  end
  assign data_in = storage;
endmodule

module sys(
  input clk,
  input [31:0] d,
  output [31:0] q
);
  wire [31:0] d_in, d_out;
  reg_32 r1(.data_out(d), .data_in(q), .clk(clk));
endmodule
